INSERT OR REPLACE INTO pages (slug, engine, category, title, description, config, content, faqs, schema_json, status, published_at, updated_at)
VALUES ('calorie-tdee-calculator', 'calculator', 'health', 'Free TDEE Calculator | gab.ae', 'Calculate your Total Daily Energy Expenditure (TDEE) and Basal Metabolic Rate (BMR) with our accurate calculator. Determine daily calorie needs for weight goals.', '{"inputs": [{"id": "age", "label": "Age", "type": "number", "default": 30, "suffix": "years"}, {"id": "gender", "label": "Gender", "type": "radio", "options": [{"value": "male", "label": "Male"}, {"value": "female", "label": "Female"}], "default": "male"}, {"id": "weight", "label": "Weight", "type": "number", "default": 70, "suffix": "kg"}, {"id": "height", "label": "Height", "type": "number", "default": 175, "suffix": "cm"}, {"id": "activity", "label": "Activity Level", "type": "select", "options": [{"value": 1.2, "label": "Sedentary (desk job, no exercise)"}, {"value": 1.375, "label": "Lightly Active (light exercise 1-3 days/week)"}, {"value": 1.55, "label": "Moderately Active (moderate exercise 3-5 days/week)"}, {"value": 1.725, "label": "Very Active (hard exercise 6-7 days/week)"}, {"value": 1.9, "label": "Extremely Active (very hard exercise, physical job)"}], "default": 1.55}], "outputs": [{"id": "bmr", "label": "Basal Metabolic Rate (BMR)", "suffix": "calories/day", "decimals": 0}, {"id": "tdee", "label": "Total Daily Energy Expenditure (TDEE)", "suffix": "calories/day", "decimals": 0}], "formula": "var bmr = gender === ''male'' ? (10 * weight) + (6.25 * height) - (5 * age) + 5 : (10 * weight) + (6.25 * height) - (5 * age) - 161; var tdee = bmr * activity;"}', '[{"heading": "What is TDEE and Why Calculate It?", "body": "Total Daily Energy Expenditure (TDEE) represents the total number of calories your body burns in a day, including your Basal Metabolic Rate (BMR) plus calories burned through physical activity. Understanding your TDEE is crucial for weight management, whether you want to lose weight, gain muscle, or maintain your current weight. By knowing your daily caloric needs, you can create an appropriate calorie deficit or surplus to reach your fitness goals safely and effectively."}, {"heading": "How TDEE is Calculated", "body": "Our calculator uses the scientifically-validated Mifflin-St Jeor equation to determine your BMR, which accounts for calories burned at rest for basic bodily functions like breathing, circulation, and cell production. This BMR is then multiplied by an activity factor (1.2 to 1.9) based on your exercise level and daily activities. The Mifflin-St Jeor equation is considered more accurate than older formulas like Harris-Benedict, providing reliable results for both men and women across different age groups."}, {"heading": "Using Your TDEE for Weight Goals", "body": "Once you know your TDEE, you can adjust your calorie intake to achieve specific goals. For weight loss, create a calorie deficit of 300-500 calories below your TDEE for safe, sustainable results (1-2 pounds per week). For weight gain or muscle building, eat 300-500 calories above your TDEE. For weight maintenance, aim to consume calories equal to your TDEE. Remember that TDEE changes as your weight, activity level, and age change, so recalculate periodically for continued accuracy."}]', '[{"q": "How accurate is the TDEE calculator?", "a": "Our TDEE calculator uses the Mifflin-St Jeor equation, which is considered the most accurate predictive formula for BMR. However, individual metabolism can vary by \u00b110-15% due to genetics, medical conditions, and other factors. Use the result as a starting point and adjust based on your actual weight changes over 2-3 weeks."}, {"q": "Should I eat exactly my TDEE calories every day?", "a": "Your TDEE represents an average daily caloric need. It''s normal for daily activity to fluctuate, so focus on weekly averages rather than hitting the exact number daily. If you''re very active some days and sedentary others, consider calculating TDEE for different activity levels and adjusting accordingly."}, {"q": "How often should I recalculate my TDEE?", "a": "Recalculate your TDEE when you lose or gain 5+ pounds, change your exercise routine significantly, or every 4-6 weeks during active weight loss/gain phases. Your metabolism adapts over time, so regular updates ensure accuracy for continued progress toward your goals."}, {"q": "What''s the difference between BMR and TDEE?", "a": "BMR (Basal Metabolic Rate) is the minimum calories needed for basic bodily functions at rest, while TDEE includes BMR plus calories burned through daily activities and exercise. BMR typically represents 60-75% of your TDEE, with the remainder coming from movement, exercise, and digestion."}, {"q": "Can I use this calculator if I have a medical condition?", "a": "While our calculator provides estimates for healthy adults, certain medical conditions (thyroid disorders, PCOS, diabetes) can significantly affect metabolism. If you have health conditions or take medications that affect metabolism, consult with a healthcare provider or registered dietitian for personalized calorie recommendations."}]', '{"@context": "https://schema.org", "@type": "WebApplication", "name": "Free TDEE Calculator", "url": "https://gab.ae/calorie-tdee-calculator", "description": "Calculate your Total Daily Energy Expenditure (TDEE) and Basal Metabolic Rate (BMR) with our accurate calculator. Determine daily calorie needs for weight goals.", "applicationCategory": "Health & Fitness", "operatingSystem": "Web Browser", "offers": {"@type": "Offer", "price": "0", "priceCurrency": "USD"}, "provider": {"@type": "Organization", "name": "gab.ae", "url": "https://gab.ae"}}', 'live', datetime('now'), datetime('now'));
UPDATE keywords SET status='live', page_slug='calorie-tdee-calculator', built_at=datetime('now') WHERE target_slug='calorie-tdee-calculator';